form:Form.form:Scripts:
		function duplicate()
{
	if (Ctrl('grdCambioTurno').TotalRowsCount() !=0)
	{
		var per = Ctrl('grdCambioTurno').GetCellSelectedXValue('oi_personal_emp');
		var desde = Ctrl('grdCambioTurno').GetCellSelectedXValue('desde');
		var hasta = Ctrl('grdCambioTurno').GetCellSelectedXValue('hasta');
		var hor = Ctrl('grdCambioTurno').GetCellSelectedXValue('oi_horario');
		var esc = Ctrl('grdCambioTurno').GetCellSelectedXValue('oi_escuadra');		

		Ctrl('grdCambioTurno').AddNew();

		var objctrl = Ctrl('grdCambioTurno').GetCellSelectedControl('oi_personal_emp');
		objctrl.SetXValue(per);		
		objctrl = Ctrl('grdCambioTurno').GetCellSelectedControl('desde');
		objctrl.SetXValue(desde);
		objctrl = Ctrl('grdCambioTurno').GetCellSelectedControl('hasta');
		objctrl.SetXValue(hasta);
		objctrl = Ctrl('grdCambioTurno').GetCellSelectedControl('oi_horario');
		objctrl.SetXValue(hor);
		SetEscuadra(); 
		objctrl = Ctrl('grdCambioTurno').GetCellSelectedControl('oi_escuadra');
		objctrl.SetXValue(esc); 

	}	
}

function SetEscuadra()
{
	var hor = Ctrl('grdCambioTurno').GetCellSelectedXValue('oi_horario');

	var Param=new NomadXML("DATA");
	Param.SetAttr("oi_horario", hor);

	var Data =new NomadXML();
	Data = GetProxy().SQLService().GetXML(Ctrl("main").getResource("QRY"), Param.ToString())

	if (Data.GetAttr("tipo") == "R")
	{
		Ctrl('grdCambioTurno').GetCellSelectedControl('oi_escuadra').SetEnabled(true);		
		Ctrl('grdCambioTurno').GetCellSelectedControl('oi_escuadra').setOptions(String2DOM(Data.FirstChild().ToString()));			
	}
	else
	{
		Ctrl('grdCambioTurno').GetCellSelectedControl('oi_escuadra').setOptions(String2DOM(Data.FirstChild().ToString()));
		Ctrl('grdCambioTurno').GetCellSelectedControl('oi_escuadra').SetXValue("");	
		Ctrl('grdCambioTurno').GetCellSelectedControl('oi_escuadra').SetEnabled(false);
	}
}

function ValidateData()
{       
	for (i=0;i<Ctrl('grdCambioTurno').TotalRowsCount();i++)	
	{     
		var flag = true;    
		if(BuscarVacios(i))
		{
		    var ctrlfechaDesde = Ctrl('grdCambioTurno').GetCellControl("desde", i);
			var ctrlfechaHasta = Ctrl('grdCambioTurno').GetCellControl("hasta", i);


			if(ctrlfechaDesde.GetXValue() >  ctrlfechaHasta.GetXValue())
			{         
				alert("La Fecha Hasta debe ser mayor que la Fecha Desde");
				flag = false;
				break;
			}
			//if(Ctrl('grdCambioTurno').GetCellSelectedXValue('desde') > Ctrl('grdCambioTurno').GetCellSelectedXValue('hasta'))
			//{         
			//	alert("La Fecha Desde debe ser mayor que la Fecha Hasta");
			//	flag = false;
			//}
			else
			{
				//for (i=0;i<Ctrl('grdCambioTurno').TotalRowsCount();i++)	
				//{		
					var ctrlesc = Ctrl('grdCambioTurno').GetCellControl("oi_escuadra", i)		
					if (ctrlesc.GetEnabled() &&  ctrlesc.GetXValue() == "")
					{
						flag = false;
						alert("Se requiere la Escuadra para Horarios de tipo Rotativo");			
						//continue;   
						break;
					}		
				//}
			}            
		}
		else
		{
		    flag = false;
		    break;
		}
	}      

	if (flag)
		Ctrl('main').DoEvent('exec');
}    


function BuscarVacios(i)
{
	 var ctrlfechaDesde = Ctrl('grdCambioTurno').GetCellControl("desde", i);
	 var ctrlfechaHasta = Ctrl('grdCambioTurno').GetCellControl("hasta", i);
	 var ctrlPersonalEmp = Ctrl('grdCambioTurno').GetCellControl("oi_personal_emp", i);
	 var ctrlHorario = Ctrl('grdCambioTurno').GetCellControl("oi_horario", i);  	



     if(ctrlPersonalEmp.GetXValue()=="") 
     {
        alert("Debe seleccionar una empresa y un legajo") ;
      	  return false;
     } 
     else if(ctrlfechaDesde.GetXValue()=="") 
     {
     	alert("la Fecha Desde no puede estar vacia");
      	  return false;
     } 
     else if(ctrlfechaHasta.GetXValue()=="") 
     {
        alert("la Fecha Hasta no puede estar vacia");
      	  return false;
     }
     else if(ctrlHorario.GetXValue()=="") 
     {
        alert("El horario no puede estar vacio");
      	  return false;
     }
     else return true;

}
